+async function getRetentionData(startDate, endDate) {
+    const users = await db.users.findMany();
+    const retained = [];
+    for (const user of users) {
+        const activity = await db.activity.findMany({ where: { userId: user.id } });
+        if (activity.length > 0) retained.push(user);
+    }
+    return retained;
+}
